var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"허신들이… 사라지기 시작했어……!","JPN":"虚神たちが……消え始めた……！","ENG":"The Hollow Gods...! They're disappearing...!","TWN":"虛神……開始消失了！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그뿐만이 아니야… 런던의 거리도, 건물도 그리고 사람들까지 전부 사라졌어……!","JPN":"それだけじゃない……ロンドンの街も、建物も。それに人々まで、全部消えた……！","ENG":"And not just that... The streets of London, the buildings, and even the people are all vanishing...!","TWN":"不僅如此……倫敦的街道、建築，甚至人們全都消失了！"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 유미나가 성공했다는 뜻인가……?","JPN":"じゃあ、ミナが成功したってこと……？","ENG":"Then that means... Yoo Mina succeeded...?","TWN":"劉米娜成功了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 검은 갑옷…? 너……?","JPN":"おい、黒い鎧……？　あんた……？","ENG":"Hey, black armor...? Are you...?","TWN":"喂，黑色盔甲？你？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇군. 나 또한 거짓된 세계의 잔재였을 뿐이니…….","JPN":"そうか。我もまた、偽りの世界の残滓に過ぎなかったと……","ENG":"I see. I, too, was merely a remnant of this false world...","TWN":"原來如此。我也不過是虛假世界的殘餘……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"소멸하는 세계가 내 존재마저 지워버리는구나. 찰나의 인연이었지만, 무운을 빌겠다.","JPN":"消滅する世界が、我の存在さえ消し去ってゆく。刹那の縁であったが、武運を祈ろう。","ENG":"And now that this world is fading, it erases my very existence. It was a fleeting bond, but I wish you fortune.","TWN":"消逝的世界連我的存在也要抹去。雖然只是短暫的緣分，但願你好運。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다른 세계의 이방인들이여…….","JPN":"異世界の異邦人たちよ……","ENG":"Outsiders from another world...","TWN":"其他世界的陌生人們……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 눈 좀 떠 봐요!","JPN":"ライカ、目を開けて！","ENG":"Laika, open your eyes!","TWN":"萊卡，快睜開眼睛！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨가 해냈어요! 이제 거의 끝났다고요……!","JPN":"ミナさんがやってくれたの！　もうほぼ終わったよ……！","ENG":"Mina did it! It's almost over now...!","TWN":"米娜成功了！現在幾乎要結束了……!！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"조금만 더… 조금만 더 버티면……","JPN":"あと少し……少しだけ耐えれば……","ENG":"Just a little more... hang in there a little longer...","TWN":"再多堅持一會兒……再多堅持一會兒的話……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이건, 신성 반응이잖아……?","JPN":"これは、神聖反応……？","ENG":"This is a Divinity response...","TWN":"這是，神聖反應啊？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미약하지만… 틀림없이 일정한 패턴으로 반응하고 있어…….","JPN":"微弱だけど……確かに一定のパターンで反応している……","ENG":"It's faint... but the pattern is responding in a regular fashion...","TWN":"雖然微弱……但確實在以一定的模式反應……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 허신은 전부 사라졌을 텐데, 어째서……?","JPN":"でも虚神は全て消えたはずなんじゃ……？　どうして……？","ENG":"But all the Hollow Gods should be gone. So why...?","TWN":"但是所有的虛神都應該消失了，為什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"이 풍경이 멸망해 버린 우리 세계의 원래 모습인가……?","JPN":"この光景が、滅亡してしまった私たちの世界の本当の姿か……？","ENG":"So this is what the world we lost originally looked like in ruin...","TWN":"這景象是我們那個已毀滅世界的原本模樣嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"Who are you...?","TWN":"你是？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국에는 아무것도 없는 황무지라니…….","JPN":"結局は何一つ存在しない荒地とは……","ENG":"In the end, it's just a wasteland...","TWN":"結果竟然是片荒蕪之地……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 덧없군. 이 세계를 구하기 위해, 파트너와 나는 고군분투해왔는데 말이지…….","JPN":"儚いな。この世界を救おうと、私とパートナーはあれほど必死に動いていたというのに……","ENG":"How fleeting. My partner and I struggled so hard to save this world...","TWN":"真是無常啊。為了拯救這個世界，我和夥伴一直在努力奮鬥……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이게 이 세계의 진실이라면, 결국 마주할 수밖에 없을지도 모르지.","JPN":"しかしこれがこの世界の真実というのならば、いずれは向き合うしかないのだろう。","ENG":"But if this is the truth of it, maybe it's something we had to face all along.","TWN":"但如果這是這個世界的真相，最終可能不得不面對。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐만요, 당신 몸이……?","JPN":"ちょっと待ってください、あなた、体が……？","ENG":"Wait, your body...!","TWN":"等等，你的身體？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 알고 있네.","JPN":"ふふ、わかっているさ。","ENG":"Haha, I know.","TWN":"呵呵，我知道。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이래서야 움직이기 쉽지 않겠군.","JPN":"これだと、思うように動くことは出来そうにないな。","ENG":"It's getting hard to move like this...","TWN":"這樣一來就不容易行動了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"미안하지만, 꼬마 레이디. 에스코트를 부탁할 수 있겠나?","JPN":"すまないが、リトルレディー。エスコートを頼めるかね？","ENG":"Sorry, little lady. Mind giving me a hand?","TWN":"抱歉，小姐。我可以請求護送嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마지막으로 자네 동료에게 전해야 할 진실이 있거든.","JPN":"最後に君の仲間に伝えなければならない真実があるんだ。","ENG":"I have one last truth to share with your comrades.","TWN":"最後，我有一個真相要告訴你的同伴。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘이… 사라져 버렸다고……?","JPN":"ノエルが……消えた……？","ENG":"Noelle... vanished...?","TWN":"洛艾兒……消失了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"거짓말이지? 설마, 이렇게 어처구니없게…….","JPN":"噓でしょ？　まさか、こんなに呆気なく……","ENG":"This has to be a joke. She couldn't have just disappeared like that...","TWN":"這不是真的吧？難道，就這樣莫名其妙地……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금껏 그렇게 다짐해왔는데…….","JPN":"今まであんなに誓ったのに……","ENG":"I swore to myself...","TWN":"到現在為止我一直都是這麼下定決心的……"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"적어도 내 주위에 소중한 사람들을 지켜내자고 결심했는데……!","JPN":"せめて周りの大切な人たちくらい、自分で守るって決めたのに……","ENG":"That I'd at least protect the people close to me...!","TWN":"至少我下定決心要保護我身邊重要的人！"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"젠장, 이래서는……! 이래서는……!","JPN":"くそ、これじゃ……！　これじゃ……！","ENG":"Damn it, not again...! Not again...!","TWN":"該死，這樣下去……！樣下去……！"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"결국, 이래서는…! 그때랑 조금도 달라진 게 없잖아……!!","JPN":"こんなんじゃ……！　あの時と何一つ変わらない……！！","ENG":"If this is how it ends, then nothing's changed at all since back then...!!","TWN":"最後，這樣下去……！和那時候一樣一點都沒有改變啊……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都在劇本之中。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마침내 늑대의 이빨이 세피라를 감싸고 있던 껍데기를 꿰뚫었군요.","JPN":"ついにオオカミの牙が、セフィラを包んでいた殻を貫きました。","ENG":"The Wolf's fangs have finally pierced the shell that held Sephira.","TWN":"終於，狼牙刺穿了包裹著生命樹的外殼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완……!","JPN":"スワン……！","ENG":"Swan...!","TWN":"史旺！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국에는 제 각본대로 잘 움직여 주었네요.","JPN":"最後は私の脚本どおりに、ちゃんと動いてくださいましたね。","ENG":"You played your part perfectly, in the end.","TWN":"最終還是按照我的劇本行動了呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 당신의 동료를 궁지에 몰아넣으면, 그 아이가 스스로 움직일 거라고 생각했으니까요.","JPN":"あなたと、あなたの仲間を窮地に追い込めば、その子自ら動いてくれると思いました。","ENG":"I knew once you and your allies were pushed into a corner, that child would act of her own accord.","TWN":"我以為把你和你的同伴逼入絕境，那孩子就會自己行動。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 각본이라고……?","JPN":"これが脚本だって……？","ENG":"You call this a script...?!","TWN":"這就是劇本嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"개수작 부리지 마! 노엘은 지금 어디에 있어!","JPN":"ふざけないで！　ノエルは今どこにいるの！","ENG":"Cut the crap! Where's Noelle?!","TWN":"別耍花招！艾兒現在在哪裡！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘이 이렇게 허무하게 사라져 버릴 리 없잖아……!","JPN":"ノエルがこんな呆気なく消え去るわけない……！","ENG":"There's no way she could've just vanished like that...!","TWN":"洛艾兒不可能就這樣無聲無息地消失了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 사라질 리 없다는 건 무슨 뜻이죠?","JPN":"さあ、消え去るわけがないとはどういう意味ですか？","ENG":"Oh? And what exactly do you mean by that?","TWN":"嗯，不可能，這是什麼意思？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알고 있을 텐데요? 노엘 라이트라는 소녀는 세피라가 만들어낸 허상에 불과해요.","JPN":"あなたもわかっているはずです。ノエル・ライトという少女は、所詮セフィラが作り出した虚像。","ENG":"You know it yourself, don't you? Noelle Wright was nothing more than an illusion created by Sephira.","TWN":"你應該也知道吧？名為洛艾兒·萊特的少女不過是生命樹製造的幻影而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 원래부터 허구였던 존재가 당신에 의해, 허무로 되돌아갔을 뿐이죠.","JPN":"つまり元から虚構に過ぎなかった存在が、あなたの手によって虚無に戻ったまでです。","ENG":"She was always a fabrication. Returning to nothing was her natural end.","TWN":"因此，本來就是虛構的存在，只是被你帶回了虛無而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽, 닥쳐…! 그런 말을 내가 믿을 것 같아……!","JPN":"くっ、黙れ……！　そんな話、信じられると思う……！？","ENG":"Kgh, shut up...! You think I'd believe that...?!","TWN":"咳，閉嘴！你以為我會相信這種話！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 믿든, 믿지 않든… 그런 건 중요하지 않습니다.","JPN":"あなたが信じる、信じないは一切関係ありません。","ENG":"Believe it or not... It makes no difference.","TWN":"不管你信，還是不信……那都不重要。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"중요한 건, 마침내 육신이라는 껍데기에서 벗어난 신적 존재가 곧 이 땅에 강림한다는 거죠.","JPN":"大事なのは、ついに肉体という殻から解放された神的存在がもうすぐこの地に降臨するということ。","ENG":"What matters is that a divine being, now freed from its mortal shell, will soon descend upon this land.","TWN":"重要的是，最終脫離了肉體軀殼的神即將降臨於此地。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신적 존재라고……?","JPN":"神的存在……？","ENG":"Divine being...?","TWN":"你說神？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, 모든 것은 이 순간을 위한 각본이었답니다.","JPN":"そうです、全てはこの瞬間のための脚本でした。","ENG":"Yes. Everything has led to this very moment.","TWN":"是的，一切都是為了這一刻的劇本。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 아이 안에 잠들어 있는 세피라 신성 에너지를 깨우기 위해서는 당신의 힘이 필요했어요.","JPN":"あの子の中に眠っているセフィラの神聖エネルギーを目覚めさせるためには、あなたの力が必要だったのです。","ENG":"To awaken the dormant Divinity energy within that child, I needed your power.","TWN":"為了喚醒那個孩子體內沉睡的生命樹神聖能量，需要你的力量。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정확히 말하자면, 당신이 직접 세피라를 품고 있던 소녀를 희생시켜야만 했죠.","JPN":"正確には、あなた自身の手で、セフィラを内包していた少女を犠牲にする必要があった。","ENG":"More specifically, you had to be the one to sacrifice the girl who held Sephira.","TWN":"準確地說，你必須親手犧牲那個封印生命樹的少女。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마치 신화 속 달을 삼켜버린 늑대처럼.","JPN":"まるで神話の中の、月を飲み込んだオオカミのように。","ENG":"Just like the wolf that devoured the moon in myth.","TWN":"就像神話中吞噬月亮的狼一樣。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그게 무슨……?","JPN":"なに、それ……？","ENG":"W-what are you talking about...?","TWN":"那，那是什麼？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 노엘을 희생시켜야 했다고……?","JPN":"私がノエルを犠牲にする必要があっただって……？","ENG":"You're saying I had to sacrifice Noelle...?","TWN":"我必須犧牲洛艾兒嗎？"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 모든 각본이 엔딩에 다다른 이 순간…….","JPN":"そして全ての脚本がエンディングに至ったこの瞬間……","ENG":"And now that the script has reached its end...","TWN":"而在劇本到達結局的這一刻……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비로소 이 땅에 천사가 내려올 겁니다.","JPN":"ようやくこの地に天使が降り立つわけです。","ENG":"An angel shall finally descend upon this world.","TWN":"天使將降臨這片土地。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자아, 그러니 그곳에서 지켜보도록 하세요, 늑대.","JPN":"さあ、そこから見守っていてください、オオカミ。","ENG":"Now then, watch closely, Wolf.","TWN":"好了，好好在那裡看著吧，狼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 신뢰하고 있는 <color=#ffd34c>그 남자</color>조차 불가능하다고 여겨 포기했던 일…….","JPN":"あなたが信頼している<color=#ffd34c>あの男</color>でさえ、不可能だと諦めたこと……","ENG":"Even <color=#ffd34c>that man</color> you trust so dearly, once deemed this impossible and gave up...","TWN":"就連你信任的<color=#ffd34c>那個男人</color>也認為不可能而放棄的事……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 각본이 엔딩에 다다른 지금, 이 자리에서 비로소 실현해 보일 테니까요.","JPN":"この脚本がエンディングに至った今、この場で実現させてみせましょう。","ENG":"But now, with this script complete... I'll prove it can be done.","TWN":"現在這個劇本已經到了結局，我會在這裡實現它。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AMY_SIX_NULL_QM","text":{"KOREA":"그래? 근데 이거 어쩌나?","JPN":"そう？　でも残念。","ENG":"Is that so? Well, that's a problem.","TWN":"是嗎？可這怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"AMY_SIX_NULL_QM","text":{"KOREA":"난 말이지. 다른 사람은 몰라도 네가 잘되는 꼴은 도저히 못 봐주겠거든?","JPN":"あたしはね、他はともかくあんたが上手くいくところは、見てられないんだよね。","ENG":"I don't know about others, but I can't stand watching you get what you want.","TWN":"我跟你說，別人我不管，但就是看不得你過得好，懂嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 익숙한 목소리네요.","JPN":"ふふ、なじみ深い声ですね。","ENG":"Haha. What a familiar voice.","TWN":"呵呵，是熟悉的聲音呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"용케도 허신으로부터 살아남은 모양이로군요, 리트리버.","JPN":"あの虚神の群れからよく生き延びましたね、レトリーバー。","ENG":"I see you survived the Hollow Gods, retriever.","TWN":"看來你竟然從虛神那裡活下來了，獵犬。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"생각했던 것보다도 훨씬 끈질기군요, 당신은.","JPN":"思っていたよりもずっとしぶといのね、あなたは。","ENG":"You're even more persistent than I gave you credit for.","TWN":"比我想像的還要頑強啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그야 당연한 거 아니겠어? 내가 지금까지 몇 번이나 생지옥을 넘어온 줄 알기나 해?","JPN":"そりゃそうだよ。今まで何度生き地獄をくぐり抜けてきたと思ってんの。","ENG":"Damn right. You know how many hells I've crawled out of to get here?","TWN":"那不是理所當然的嗎？你知道我到現在為止經歷了多少次生死攸關的時刻嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그리고 내가 원래 한번 물면 잘 안 놔주는 편이거든?","JPN":"それにあたしは、もともと一度噛みついたらなかなか離さない方でね？","ENG":"And once I bite down, I don't let go easy.","TWN":"而且我本來就是一旦咬住就不鬆口的類型，對吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"와앙~! 어때, 무섭지?","JPN":"ガオー！　ほら、怖いでしょ？","ENG":"Grrr...! Scared yet?","TWN":"啊嗚！怎麼樣，可怕吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미……?","JPN":"エイミー……？","ENG":"Amy...?","TWN":"艾米？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 유미나! 눈치 없게 끼어들지 말고, 어디 짜져 있으라고.","JPN":"ミナ！　引っ込んでな、空気も読めないの？","ENG":"Hey, Yoo Mina! Don't go butting in like an amateur. Sit tight.","TWN":"喂，劉米娜！少不識趣地插嘴，給我待在一邊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"잠깐 정도라면, 시간을 벌어줄 테니까 말이야.","JPN":"少しくらいなら、時間稼ぎしてやるからさ。","ENG":"I'll buy you some time—just a little.","TWN":"如果只是暫時的話，我會幫你爭取時間的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리야? 시간을 벌어준다니?","JPN":"どういうこと？　時間稼ぎって？","ENG":"What are you talking about, buying time?","TWN":"什麼意思？你說幫我爭取時間？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쯧, 하여간 그새 잊어버렸어? 난 저 망할 년이랑 결착을 내러 여기까지 온 거야.","JPN":"ちっ、もう忘れたの？　あたしはあのクソ女と決着を付けるためにここまで来たんだよ。","ENG":"Tch, seriously? Did you already forget? I came all the way here to settle things with that damn woman.","TWN":"嘖，怎麼這麼快就忘了？我是來這裡和那個該死的女人做個了結的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그걸 위해서, 지금까지 널 이용한 거고.","JPN":"そのために、今まであんたを利用した。","ENG":"And to do that, I used you.","TWN":"為了那個，我一直在利用你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미…….","JPN":"エイミー……","ENG":"Amy...","TWN":"艾米……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아, 진짜! 여자끼리 징그럽게 그런 표정 짓지 말라고.","JPN":"ああ、もう！　女同士でそのキモイ顔やめてくれる？","ENG":"Ugh, don't make that face! That clingy expression doesn't suit you.","TWN":"啊，真是的！女孩子之間不要做那種噁心的表情。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"얼른 꼬맹이한테 가 봐, 그 재수없는 꼬맹이가 너한테 볼 일이 있는 모양이니까.","JPN":"さっさとガキのところに行きなって。あの生意気なガキがあんたに用があるみたいだから。","ENG":"Go check on the brat. Looks like she's got something to say to you.","TWN":"快去找那個小鬼吧，那個討厭的小鬼好像有事找你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알겠어…! 고마워, 에이미……!","JPN":"わ、わかった……！　ありがとう、エイミー……！","ENG":"R-right...! Thanks, Amy...!","TWN":"啊，知道了！謝謝你，艾米！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 방해꾼도 사라졌겠다…….","JPN":"よし、これで邪魔者はいなくなったな……","ENG":"Well then, now that there's no one to bother us...","TWN":"那麼，既然搗亂的人也消失了……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럭저럭 각오하는 게 좋을 거야, 스완.","JPN":"そこそこ覚悟しておいた方がいいよ、スワン。","ENG":"You better brace yourself, Swan.","TWN":"做好心理準備吧，史旺。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"네 수법은 이미 잘 알고 있다고. 저번처럼 호락호락하게 당하지는 않아.","JPN":"あんたの手口はよく知ってる。この前みたいに、そう易々とやられるつもりはないから。","ENG":"I know your tricks now. I'm not falling for the same crap again.","TWN":"你的手段我已經很清楚了。這次不會像上次那樣輕易上當。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"구태여 이런 타이밍에 늑대를 보내고, 당신이 저와 맞서다니…….","JPN":"あえてこのタイミングでオオカミを送り出し、私に立ち向かうとは……","ENG":"Sending the Wolf away and facing me yourself...","TWN":"偏偏在這個時候讓狼離開，留下你要和我對抗……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 이건 치밀한 당신 캐릭터와는 맞지 않은 행동이네요, 퍼스트윙.","JPN":"どうでしょう、これは緻密なあなたのキャラとは合わない行動ですね、ファーストウイング。","ENG":"That's not like your usual calculating self, Firstwing.","TWN":"嗯，這可不像你一貫精明的風格，弗斯特薇。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마, 이것도 대장님께서 시키신 걸까요?","JPN":"まさか、これも隊長からの指示ですか？","ENG":"Did Commander gave you this order?","TWN":"難道，這也是隊長讓你做的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워, 이건 육익이랑은 관계없어.","JPN":"うるさいな、これは六翼とは関係ない。","ENG":"Shut up. This has nothing to do with Six Wings.","TWN":"閉嘴，這和六翼無關。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나는 그냥 네가 싫을 뿐이야. 처음 본 순간부터 마음에 안 들었다고……!","JPN":"あたしはただあんたが嫌いなだけだ。初めて見た時から気に入らなかったのさ……！","ENG":"I just can't stand you. Hated you from the second I laid eyes on you.","TWN":"我就是討厭你。從第一次見面的時候開始就討厭你！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 빌어먹을 암군에게 빌붙은 하수인 주제에……!","JPN":"あのクソったれな暗君に媚びへつらう手先ふぜいが……！","ENG":"Clinging to the Ignorant Monarch like some servant...!","TWN":"你這個依附於該死暗君的走狗！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"암군의 하수인이라…….","JPN":"暗君の手先……","ENG":"A servant to the Ignorant Monarch...","TWN":"暗君的僕人啊……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요…….","JPN":"そうですか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무래도 당신과는 매듭지어야 할 게 남은 모양이에요.","JPN":"どうやらあなたとは、まだけりを付けなければいけないようですね。","ENG":"Looks like we have some unfinished business between us, after all.","TWN":"看來我和你之間還有未了的結。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 이걸로 괜찮을까요? 앞선 허신과의 전투로 이미 당신은 체력을 다했을 텐데 말이죠.","JPN":"ですが、それでいいのですか？　さっきの虚神との戦いで、あなたの体力はもう底をついているはずでは？","ENG":"But are you sure about this? After that fight with the Hollow Gods, you must be nearly spent.","TWN":"但是你真的可以嗎？之前與虛神的戰鬥中，你的體力應該已經耗盡了吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"흥, 이제 와서 내 걱정이라도 해주려는 거야?","JPN":"ふん、今更あたしの心配？","ENG":"Hmph. Are you worried about me?","TWN":"哼，現在才來關心我嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이거 눈물 나게 고마운데?","JPN":"ありがたくて涙が出そうなんだけど。","ENG":"How touching. I'm almost in tears.","TWN":"這讓我感動得想流淚呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 저는 단지 고민하고 있을 뿐이랍니다.","JPN":"いいえ、私はただ悩んでいるだけです。","ENG":"Not at all. I'm simply wondering.","TWN":"不，我只是在思考。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막에는 당신에게 어떤 목줄을 채워야 할지 말이죠, 리트리버.","JPN":"レトリーバー、あなたに最後に付ける首輪はどのようなものがいいかと。","ENG":"What kind of leash I should put on you when this is over, retriever.","TWN":"最後，給你套上什麼？的項圈呢，獵犬。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"흥! 어디 해볼 수 있으면 해보라고!","JPN":"ふん！　やれるもんならやってみな！","ENG":"Hmph! Just try me. Let's see you pull that off!","TWN":"哼！本事就來試試看吧！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"……여기에요, 미나 씨! 여기라고요!","JPN":"……ここです、ミナさん！　ここ！","ENG":"...Over here, Mina! This way!","TWN":"……在這裡，米娜！？是這裡！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트…? 그리고 탐정 아저씨……?","JPN":"フェリセット……？　それに探偵のおじさんも……？","ENG":"Félicette...? And Detective...?","TWN":"費莉塞特？還有偵探先生？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 당신 몸이 왜 그래? 조금씩 흩어지고 있잖아?","JPN":"えっ、その体どうしたの？　ちょっとずつ散ってるじゃない……","ENG":"Wait, what's wrong with your body? You're fading!","TWN":"等等，你的身體怎麼了？正在一點點消散？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 내게 주어진 시간이 얼마 남지 않았다는 뜻이겠지.","JPN":"おそらく私に与えられた時間が、残り少ないということだろう。","ENG":"I suppose my time's nearly up.","TWN":"也許這表示我剩下的時間不多了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 잘 듣게, 미나 양.","JPN":"そんなことより、よく聞きたまえ、ミナ君。","ENG":"More importantly, listen closely, Mina.","TWN":"聽好了，米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 스완의 목적은 단순히 고향 세계를 되돌리는 게 아닐지도 몰라.","JPN":"もしかするとスワンの目的は、単純に故郷の世界を元に戻すことではない可能性がある。","ENG":"Swan might not just be trying to restore her home world.","TWN":"也許史旺的目的不僅僅是恢復故鄉的世界。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완이 천사를 강림시키려는 건, 다른 목적이 있을지도 모른다네.","JPN":"スワンが天使を降臨させようとするのは、何か他の目的のためなのかもしれないのだ。","ENG":"She may have a different goal entirely for summoning that angel.","TWN":"史旺想要召喚天使，可能另有目的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다른 목적이라니, 갑자기 뜬금없이 무슨 소리야?","JPN":"急に他の目的って？","ENG":"A different goal? Where's this coming from?","TWN":"其他目的？怎麼突然莫名其妙說這個？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 근거라도 있어?","JPN":"何か根拠でもあるの？","ENG":"Do you have proof?","TWN":"有什麼根據嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"근거는 없네. 증거 또한 있을 리 만무하지. 이건 어디까지나 내 직감에 불과해.","JPN":"根拠はない。証拠もまた、存在しない。これはあくまでも私の直感に過ぎない。","ENG":"No evidence. No proof. Just a hunch.","TWN":"沒有根據，證據也沒有。這不過是我的直覺而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 나는 모든 판단을 자네에게 맡기려고 해.","JPN":"だから私は全ての判断を君に任せようと思っている。","ENG":"And that's why I leave the decision to you.","TWN":"所以我打算把所有的判斷交給你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대적자라는 존재가 있다네.","JPN":"敵対者という存在がいる。","ENG":"There is a being called the Antagonist.","TWN":"有一種存在叫做敵對者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한 세계의 의지로부터 선택을 받은 존재지.","JPN":"それは、世界の意志から選ばれた存在だ。","ENG":"This being is chosen by the will of a world.","TWN":"是被一個世界的意志所選擇的存在。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대적자라고? 지금 대적자라고 했어?","JPN":"敵対者？　今、敵対者と言った？","ENG":"Antagonist? Did you just say Antagonist?","TWN":"敵對者？你剛剛是說敵對者嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네 설마 대적자에 대해서 알고 있나? 그럼, 이야기가 빠르겠군.","JPN":"まさか君、敵対者について知っているのかね？　だったら話は早い。","ENG":"So you know about the Antagonist? That makes things simpler.","TWN":"你難道知道敵對者的事情嗎？那解釋起來就快了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"전에 말한 이방인과 만난 뒤로, 나는 줄곧 우리 세계의 대적자를 찾아왔다네.","JPN":"前に話した異邦人と出会ってから、私はずっと私の世界の敵対者を探していた。","ENG":"Ever since I met another outsider, I've been searching for the Antagonist of our world.","TWN":"自從遇到之前提到的外邦人後，我一直在尋找我們世界的敵對者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 마침내 어느 소녀와 만나게 되었지.","JPN":"そしてついに、とある少女と出会った。","ENG":"And eventually, I met a girl.","TWN":"然後終於遇到了某個少女。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀는 로열 오페라 하우스의 프리마돈나였어.","JPN":"彼女はロイヤルオペラハウスのプリマドンナだった。","ENG":"She was the prima donna of the Royal Opera House.","TWN":"她曾是皇家歌劇院的首席女主角。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"겉모습은 가녀린 소녀처럼 보였지만, 사실은 누구보다 강한 의지를 지닌 여인이었네.","JPN":"見た目はか弱い少女だったが、本当は誰よりも強い意志を持っている女性だった。","ENG":"She looked like a delicate young woman, but had a stronger will than anyone I've known.","TWN":"外表看似纖弱的少女，實際上是比任何人都擁有強大意志的女人。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설령 목숨을 위협받는 상황에서도, 배우로서 우아하게 살아가려고 했으니까.","JPN":"その命が危うい状況でさえも、俳優として優雅に生きる姿勢を崩そうとしなかったからね。","ENG":"Even when her life was on the line, she lived with grace, like a true performer.","TWN":"即使在生命受到威脅的情況下，她也想作為演員優雅地活下去。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만, 설마 그 꼬맹이 스완이 대적자였다는 거야?","JPN":"じゃあ、まさかあのちびっ子スワンが敵対者だったと言うの？","ENG":"Wait! Are you telling me that little Swan is the Antagonist?","TWN":"等一下，難道那個小史旺是敵對者嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 그녀야말로 틀림없이 우리 세계가 남긴 최후의 걸작이지.","JPN":"その通り。彼女こそが私の世界が産んだ、まごうことなき最後の傑作さ。","ENG":"Yes. She is, without a doubt, our world's final masterpiece.","TWN":"是的。她無疑是我們世界留下的最後傑作。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"최후의 걸작……?","JPN":"最後の傑作……？","ENG":"Final masterpiece...?","TWN":"最後的傑作？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 나는 결국 마지막까지 그 사실을 전하지 못했어.","JPN":"しかし私は結局、最後までその事実を伝えることができなかった。","ENG":"But I never told her. Not even at the end.","TWN":"但最終我還是沒能告訴她這個事實。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"망설이고 말았지. 이 세계의 모든 미지를 상대한다는 건, 그만큼 고독한 일이니까.","JPN":"迷ってしまったんだ。この世界の全ての未知を相手にするということは、それだけの孤独を背負うことに他ならないから。","ENG":"I hesitated. Tackling all the unknown in this world is a lonely task, after all.","TWN":"我猶豫了，因為獨自面對這個世界的所有未知，實在是一件孤獨的事情。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 누구보다도 내가 가장 잘 알고 있으니까.","JPN":"それは誰よりも私が一番よく知っている。","ENG":"And I know that better than anyone.","TWN":"因為這件事我比任何人都清楚。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서? 지금 무슨 말을 하고 싶은 거야?","JPN":"で？　何が言いたいの？","ENG":"So? What are you trying to tell me?","TWN":"所以呢？你現在想說什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완한테 동정이라도 하라고?","JPN":"スワンに同情でもしろって？","ENG":"Do you want me to pity her now?","TWN":"是想讓我同情史旺嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"동정? 틀렸네. 이건 동정이 아니야.","JPN":"同情？　違うな。これは同情なんかではない。","ENG":"Pity? No. That's not it.","TWN":"同情？錯了。這不是同情。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 지금 <color=#ffd34c>만약</color>의 이야기를 하는 거라네.","JPN":"私は今、<color=#ffd34c>もしも</color>の話をしている。","ENG":"This is purely hypothetical. A <color=#ffd34c>what if</color>, if you will.","TWN":"我現在是在講<color=#ffd34c>設想</color>的故事。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"만약……?","JPN":"もしも……？","ENG":"A what if...?","TWN":"設想？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 만들어진 허상일 뿐. 그리고 이곳에 있는 스완은 내가 아는 그녀와는 다른 존재지.","JPN":"私は作られた虚像に過ぎない。そしてここにいるスワンは、私の知っている彼女とは違う存在だ。","ENG":"I'm just an illusion. And this Swan is not the one I know.","TWN":"我只是一個被創造的幻影。而這裡的史旺與我所認識的她是不同的存在。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 스완은 스스로가 대적자라는 것을 자각하고 있을지도 몰라.","JPN":"もしかすると、スワンは自分が敵対者であることを自覚しているのかもしれない。","ENG":"But perhaps Swan knows she's the Antagonist.","TWN":"也許史旺已經意識到自己是敵對者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"알다시피, 대적자는 마왕으로부터 세계를 수호하는 존재야.","JPN":"知っての通り、敵対者は魔王から世界を守護する存在だ。","ENG":"As you know, the Antagonist is someone meant to protect a world from the Demon Lord.","TWN":"如你所知，敵對者是從魔王手中守護世界的存在。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건 어디까지나 내 직감이지만…….","JPN":"あくまでも私の直感に過ぎないが……","ENG":"It's just a gut feeling, but...","TWN":"這只是我的直覺……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"만약 그렇다면, 그녀는 어떤 <color=#ffd34c>대의</color>를 위해, 스스로 악을 자처하고 있을 가능성이 있어.","JPN":"もしそうだとしたら、彼女はとある<color=#ffd34c>大義</color>のために、自ら悪を自称している可能性がある。","ENG":"Maybe, just maybe, she took on the role of a villain for a <color=#ffd34c>greater cause</color>.","TWN":"如果是這樣的話，她可能是為了某種<color=#ffd34c>大義</color>，自願扮演惡人的角色。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀는 대적자로서 자신만의 방식으로, 자신만의 싸움을 하고 있을지도 몰라.","JPN":"彼女は敵対者として、自分だけの方法で、自分だけの戦いをしているのかもしれない。","ENG":"Maybe this is her way of fighting as the Antagonist.","TWN":"她可能正在以她自己的方式，以她自己的戰鬥方式，作為敵對者進行戰鬥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 그녀는 이해할 수도, 가늠할 수조차 없는 고독한 인생을 살아왔던 걸지도 모르지.","JPN":"もしかすると彼女は、理解も、想像もできないほど孤独な人生を生きてきたのかもしれないのだ。","ENG":"Maybe she's lived a life so lonely, no one could even comprehend it.","TWN":"或許她過著我們無法理解也無法想像的孤獨的生活。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"악을 자처한다고……?","JPN":"悪を自称する……？","ENG":"Taking on the role of a villain...?","TWN":"扮演惡人？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"웃기지 마! 나는 그딴 거 인정 못 해……!","JPN":"ふざけないで！　そんなの認めない……！","ENG":"Don't make me laugh! I'm not buying that...!","TWN":"別開玩笑了！我才不承認那種事……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신 세계에서 스완이 어땠는지는 몰라도, 우리 세계에서 스완은 1급 수배범이었어……!","JPN":"あなたの世界のスワンはどうだったか知らないけど、私の世界のスワンは1級手配犯だった……！","ENG":"I don't care how she was in your world! Here, she's a wanted first-degree criminal...!","TWN":"我不知道在你的世界裡史旺是怎樣的，但在我們的世界裡，史旺是一級通緝犯！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사실로 밝혀진 것만 해도, 이미 수많은 사람을 죽였다고!","JPN":"既に数えきれないほどの人を殺した人物と知られている！","ENG":"Even just what's been confirmed, she's killed countless people!","TWN":"僅僅是已經查明的真相，就已經殺了無數人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완이 대적자라고?","JPN":"スワンが敵対者だって？","ENG":"Swan is the Antagonist?","TWN":"史旺是敵對者？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"백번 양보해서 그 대의라는 건 뭔데? 그 대의가 노엘보다도 더 중요한 거야?","JPN":"百歩譲ってそうだとして、その大義って何？　ノエルよりも大事なもの？","ENG":"Even if I gave her the benefit of the doubt... what greater cause could justify this? Is that more important than Noelle?","TWN":"就算我退讓一百步，你所說的大義到底是什麼？那大義比洛艾兒還重要嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그걸 위해서, 노엘을 희생시켜야 했냐고……!","JPN":"そのために、ノエルが犠牲にならなければいけないほど大事なものなの……！？","ENG":"Did she have to sacrifice Noelle for that...?!","TWN":"為了那個，就必須犧牲洛艾兒嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"젠장, 나는……!","JPN":"くそ、私は……！","ENG":"Damn it, I–!","TWN":"可惡，我！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 말이 맞네.","JPN":"君の言うとおりだ。","ENG":"You're right.","TWN":"你說的沒錯。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현시점의 나는 그 대의가 무엇인지 알 수 없어.","JPN":"現時点の私にはその大義が何なのか、知り得ない。","ENG":"Right now, I don't know what that greater cause is.","TWN":"現在，我還不知道那個更偉大的使命是什麼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그게 무엇이든, 함부로 타인의 목숨을 희생해서는 안 되는 거겠지.","JPN":"そしてそれが何であれ、無闇に他人の命を犠牲にすることは許されないだろう。","ENG":"And no cause justifies sacrificing someone else.","TWN":"而且無論是什麼，都不應該隨意犧牲他人的生命。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 아직 늦지는 않았네.","JPN":"しかしまだ間に合う。","ENG":"But it's not too late.","TWN":"但現在還不算太遲。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어떤 이유인지는 모르겠지만, 스완은 아직 <color=#ffd34c>그 아이</color>를 희생시키지 않은 모양이니까.","JPN":"理由はわからないが、スワンはまだ<color=#ffd34c>あの子</color>を犠牲にしてはいないようだからね。","ENG":"For whatever reason, it seems Swan hasn't sacrificed <color=#ffd34c>her</color> yet.","TWN":"不知道是什麼？因，史旺似乎還沒有犧牲<color=#ffd34c>那個孩子</color>。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 아이는 아직 이곳에 있네, 그건 틀림없는 진실이야.","JPN":"あの子はまだここにいる。それは間違いようのない真実だ。","ENG":"She is still here. That much is certain.","TWN":"那個孩子還在這裡，這無疑是事實。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금 노엘이 살아있다고? 그게 정말이야?","JPN":"ノエルが生きている？　本当に？","ENG":"Noelle is still alive? Are you sure?","TWN":"洛艾兒現在還活著？那是真的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네, 미나 양.","JPN":"簡単な話だよ、ミナ君。","ENG":"It's simple, my dear Mina.","TWN":"這是個簡單的故事，米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완은 그 아이의 본질이 세피라. 즉, 세계를 만드는 법칙의 일부라고 했어.","JPN":"スワンはあの子の本質がセフィラ、つまり、世界を作る法則の一部だと言った。","ENG":"Swan said it herself that the girl's essence is Sephira. A part of the law of creating a world.","TWN":"史旺說那個孩子的本質是生命樹，也就是構成世界法則的一部分。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 그 아이가 진심으로 바라는 건 현실이 되어버린다는 뜻이지.","JPN":"言い換えれば、あの子が本心から願うことは現実になるということさ。","ENG":"In other words, her wishes become reality.","TWN":"換句話說，那孩子真心渴望的東西會變成現實。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 노엘은 사라져 버렸어.","JPN":"でもノエルは消えた。","ENG":"But Noelle disappeared.","TWN":"但是洛艾兒消失了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 노엘이 사라지면서 이곳의 런던도, 사람들이랑 허신까지 전부 사라져……","JPN":"そしてノエルとともにこのロンドンも、人々も、虚神まで全部消え……","ENG":"And when she vanished along with London, the other people, and even the Hollow Gods...","TWN":"然後隨著洛艾兒的消失，這裡的倫敦、人們以及虛神也全都消失了……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐!?","JPN":"待って！？","ENG":"Wait!","TWN":"等等？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 당신은……!?","JPN":"まさかあなたは……！？","ENG":"Could it be...?!","TWN":"難道你是……！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 아무래도 눈치챈 모양이군.","JPN":"ふふ、どうやら気が付いたようだね。","ENG":"Haha. So you figured it out.","TWN":"呵呵，看起來你終於發現了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 자네 추측대로 나는 아직 이곳에 있네.","JPN":"そう、君の推測どおり、私はまだここにいる。","ENG":"Yes, just as you guessed, I'm still here.","TWN":"是的，正如你所猜測的，我還在這裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그저 허상에 불과한 육신이지만, 그 마저도 조금씩 사라져 가고 있지만…….","JPN":"ただの虚像に過ぎない肉体で、それさえも少しずつ消えてはいるが……","ENG":"My body's just a fading illusion now...","TWN":"雖然只是虛幻的肉體，但即便如此也在逐漸消逝……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그럼에도 나는 여기에 있네.","JPN":"それでも私は、ここにいる。","ENG":"But even so, I exist here.","TWN":"但即便如此，我仍在這裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다는 건, 그 아이가 어디선가 나를 관측하고, 내가 존재하기를 바란다는 뜻 아닐까?","JPN":"ということは、あの子がどこかで私を観測し、私が存在し続けることを願っているということではないかね？","ENG":"And that means someone out there still sees me, still wants me to be.","TWN":"那就是說，那孩子在某處觀察我，並希望我存在的意思吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 이곳에 있다는 것 자체가 그 아이가 살아있다는 증거가 아닐까?","JPN":"私がここにいるということ自体が、あの子が生きている証拠ではないのかね？","ENG":"My existence itself proves that she is still alive.","TWN":"我在這裡本身不就是那個孩子還活著的證據嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 자신의 존재를 알리기 위해, 무의식적으로 나를 안배해 둔 것일지도 모르지.","JPN":"もしかすると、自分の存在を知らしめるために、無意識に私を残しておいたのかもしれない。","ENG":"Maybe she unconsciously arranged it so that I was left here so someone would figure it out?","TWN":"也許是為了讓自己的存在被知道，才無意識地安排了我。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수수께끼 풀이가 내 업이니까.","JPN":"謎解きが私の仕事なのだから。","ENG":"Solving mysteries is my job, after all.","TWN":"因為解謎是我的工作。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 그래서? 노엘은 지금 어디 있는 건데?","JPN":"ちょっと待って、それで？　ノエルは今どこにいるの？","ENG":"Wait, so? Where is Noelle now?","TWN":"等一下，所以？洛艾兒現在在哪裡？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어디서 우리를 지켜보고 있다는 거야?","JPN":"どこで私たちを見てるっていうの？","ENG":"Are you saying she is watching us from somewhere?","TWN":"究竟是在哪裡在看著我們？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨, <color=#ffd34c>달</color>이에요…….","JPN":"ミナさん、<color=#ffd34c>月</color>です……","ENG":"Mina, it's the <color=#ffd34c>moon</color>...","TWN":"米娜，<color=#ffd34c>月亮</color>……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미약하지만, 망원경이 하늘에 떠 있는 달 방향에서 신성 반응을 포착하고 있어요.","JPN":"微弱だけど、望遠鏡が空に浮かぶ月の方向から神聖反応を捕捉しています。","ENG":"It's faint, but the Telescope detected the Divinity response from the direction of the moon.","TWN":"雖然微弱，但望遠鏡在月亮的方向捕捉到了神聖反應。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 달이라…….","JPN":"ふふ、月か……","ENG":"Haha, the moon...","TWN":"呵呵，月亮啊……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"재미있는 발상이로군. 달에 극장이라도 마련해 둘 셈이었나?","JPN":"面白い発想だ。月に劇場でも用意するつもりだったのか？","ENG":"That's an interesting idea. Was she preparing to place a theater up there?","TWN":"真是有趣的想法。是打算在月球上建個劇院嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 신성 반응이라고……?","JPN":"神聖反応……？","ENG":"Hold on. Did you say Divinity response...?","TWN":"等一下，你說是神聖反應？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그걸로 노엘의 위치를 알 수 있다는 거야?","JPN":"それでノエルの位置がわかるの？","ENG":"You mean we can use that to find Noelle?","TWN":"那樣就能知道洛艾兒的位置嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이 좌표가 정말 노엘의 위치인지는 모르겠지만…….","JPN":"この座標が本当にノエルの位置かはわかりませんが……","ENG":"I don't know for sure if these coordinates are her location...","TWN":"我不知道這個座標是否真的是洛艾兒的位置……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"6종 침식체들이 전부 소멸한 뒤에 이곳에 포착되는 유일한 신성 반응이에요……!","JPN":"第6種侵食体が全部消滅してから、ここで捕捉される唯一の神聖反応です……！","ENG":"But it's the only Divinity response that's appeared since the Category 6 C.O.s all vanished...!","TWN":"6類侵蝕體全部被消滅後，這裡是捕捉到的唯一神聖反應！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까 이건 어쩌면……!","JPN":"だから、これがもしかしたら……！","ENG":"Which means, maybe...!","TWN":"所以這可能是……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘……!","JPN":"ノエル……！","ENG":"Noelle...!","TWN":"洛艾兒！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};